size (5,5)
start (0,0)
goal (4,4)

item "Treasure Map" {
  at (0,1)
  message "This map reveals everything!"
}

item "Gold Coin" {
  at (2,2)
  message "Shiny gold coin"
}

item "Silver Key" {
  at (3,3)
  message "Unlocks something important"
}

obstacle {
  at (1,2), (2,1)
  requires "Treasure Map"
}

plugin edu.curtin.gameplugins.Teleport
plugin edu.curtin.gameplugins.Reveal
plugin edu.curtin.gameplugins.Prize

script !{
import time

last_move_time = [time.time()]

def execute(game):
    print("Python script: execute() called")

    def on_player_move(row, col):
        current_time = time.time()
        elapsed = current_time - last_move_time[0]

        if elapsed > 5:
            directions = [(0, 1), (1, 0), (0, -1), (-1, 0)]
            for dr, dc in directions:
                r = row + dr
                c = col + dc

                if 0 <= r < game.getRows() and 0 <= c < game.getCols():
                    if not game.hasObstacle(r, c) and not game.hasGoal(r, c) and not game.hasInventory(r,c):
                        game.addObstacle(r, c, ["Penalty Blocker"])
                        game.setVisible(r, c, True)
                        game.printMap()
                        print("Penalty obstacle added at row " + str(r) + ", col " + str(c))
                        break

        last_move_time[0] = current_time

    game.registerPlayerMoveCallback(on_player_move)

}